转载来源这是我转载的老外的教程，视频来源：跳转到 Youtube查看 视频教程 视频简介在这个视频中，我们学习了如何使用esp8266-12e和iOS来控制led。 模块本身不到10美元，所以与其他物联网设备相比，制作这个项目并不需要太多的费用。 视频中的程序代码（不包含IOS APP代码）123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103#include &lt;ESP8266WiFi.h&gt;//////////////////////// WiFi Definitions ////////////////////////const char WiFiAPPSK[] = "esp8266-12e";/////////////////////// Pin Definitions ///////////////////////const int LED_PIN = 16; // Thing's onboard, green LEDWiFiServer server(80);void setupWiFi()&#123; WiFi.mode(WIFI_AP); // Do a little work to get a unique-ish name. Append the // last two bytes of the MAC (HEX'd) to "ThingDev-": uint8_t mac[WL_MAC_ADDR_LENGTH]; WiFi.softAPmacAddress(mac); String macID = String(mac[WL_MAC_ADDR_LENGTH - 2], HEX) + String(mac[WL_MAC_ADDR_LENGTH - 1], HEX); macID.toUpperCase(); String AP_NameString = "ESP-" + macID; char AP_NameChar[AP_NameString.length() + 1]; memset(AP_NameChar, 0, AP_NameString.length() + 1); for (int i=0; i&lt;AP_NameString.length(); i++) AP_NameChar[i] = AP_NameString.charAt(i); WiFi.softAP(AP_NameChar, WiFiAPPSK);&#125;void initHardware()&#123; Serial.begin(115200); pinMode(LED_PIN, OUTPUT); digitalWrite(LED_PIN, LOW); // Don't need to set ANALOG_PIN as input, // that's all it can be.&#125;void setup() &#123; initHardware(); setupWiFi(); server.begin();&#125;void loop() &#123; // Check if a client has connected WiFiClient client = server.available(); if (!client) &#123; return; &#125; // Read the first line of the request String req = client.readStringUntil(''); Serial.println(req); client.flush(); // Match the request int val = -1; // We'll use 'val' to keep track of both the // request type (read/set) and value if set. if (req.indexOf("/led/0") != -1) val = 1; // Will write LED high else if (req.indexOf("/led/1") != -1) val = 0; // Will write LED low // Set GPIO5 according to the request if (val &gt;= 0) digitalWrite(LED_PIN, val); client.flush(); // Prepare the response. Start with the common header: String s = "HTTP/1.1 200 OK
"; s += "Content-Type: text/html

"; s += "&lt;!DOCTYPE HTML&gt;
&lt;html&gt;
"; // If we're setting the LED, print out a message saying we did if (val &gt;= 0) &#123; s += "LED is now "; s += (val)?"off":"on"; &#125; else &#123; s += "Invalid Request.&lt;br&gt; Try /led/1, /led/0, or /read."; &#125; s += "&lt;/html&gt;
"; // Send the response to the client client.print(s); delay(1); Serial.println("Client disonnected"); // The client will actually be disconnected // when the function returns and 'client' object is detroyed&#125;
